            vint8m1_t vPa3_i8 = __riscv_vundefined_i8m1();
            vint8m1_t vPa4_i8 = __riscv_vundefined_i8m1();
            vint8m1_t vPb_i8 = __riscv_vundefined_i8m1();
            vint8m1_t vPb2_i8 = __riscv_vundefined_i8m1();
            vint8m1_t vPb3_i8 = __riscv_vundefined_i8m1();
            vint8m1_t vPb4_i8 = __riscv_vundefined_i8m1();
