            vPa2_i8 = __riscv_vle8_tu(vPa2_i8, pA2, vl);
            vPa3_i8 = __riscv_vle8_tu(vPa3_i8, pA3, vl);
            vPa4_i8 = __riscv_vle8_tu(vPa4_i8, pA4, vl);
