            vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
            vPb2_i8 = __riscv_vle8_tu(vPb2_i8, pB2, vl);
            vPb3_i8 = __riscv_vle8_tu(vPb3_i8, pB3, vl);
            vPb4_i8 = __riscv_vle8_tu(vPb4_i8, pB4, vl);

            //bump pointers and update loop counter
            colCnt -= vl;
            pA += vl;
            pA2 += vl;
            pA3 += vl;
            pA4 += vl;
            pB += vl;
            pB2 += vl;
            pB3 += vl;
            pB4 += vl;

            //set the proper avl/SEW/LMUL values for vd4dot
            vl >>= 2;
            vl = __riscv_vsetvl_e32m1(vl);

            //acc += src1 * src2
            vAcc0 = __riscv_vd4dots_vv_i32m1_tu(vAcc0, vPa_i8, vPb_i8, vl);
            vAcc1 = __riscv_vd4dots_vv_i32m1_tu(vAcc1, vPa2_i8, vPb_i8, vl);
            vAcc2 = __riscv_vd4dots_vv_i32m1_tu(vAcc2, vPa3_i8, vPb_i8, vl);
            vAcc3 = __riscv_vd4dots_vv_i32m1_tu(vAcc3, vPa4_i8, vPb_i8, vl);

