                                   (q7_t*)in_tmp_buf,
                                   out_tensor_ch,
                                   in_tensor_ch * ker_dim * ker_dim,
                                   bias_lshift,
                                   out_rshift,
                                   bias,
                                   pOut);
                /* counter reset */
