//                 q31_t     inA11, inA12;
//                 q31_t     inB1;

//                 pA  = (q7_t *) read_and_pad_reordered((void *)pA, &inA11, &inA12);
//                 inB1 = *__SIMD32(pB)++;
//                 sum  = NDS_DSP_KMADA(sum, inA11, inB1);
//                 inB1 = *__SIMD32(pB)++;
//                 sum  = NDS_DSP_KMADA(sum, inA12, inB1);
//             }

//             colCnt = (in_tensor_ch * ker_dim * ker_dim) & 0x3;
//             while (colCnt)
//             {
//                 q7_t      inA1 = *pA++;
//                 q15_t     inB1 = *pB++;
//                 sum += inA1 * inB1;
//                 colCnt--;
//             }

//             /* add bias back into sum */
//             sum += ((q31_t)(bias[i]) << bias_lshift) + NN_ROUND(out_rshift);

//             *pOut = (q7_t) NDS_DSP_SATS(((q31_t)sum >> out_rshift), 8);
//             pOut++;
//         }
//     }
// #else
    if (pBuffer != in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int       i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
            q15_t    *pB = in_tmp_buf;
            /* each time it process 4 entries */
            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;

            while (colCnt)
            {

                q31_t     inA1, inA2;
                q31_t     inB1, inB2;

                pA = (q7_t *) read_and_pad_reordered((void *)pA, &inA1, &inA2);

                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA1, inB1);
                inB2 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA2, inB2);

                colCnt--;
            }
            //since in_tensor_ch is multiple of 4 (input constraints), the
            //following codes will not be reached
            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
            // while (colCnt)
            // {
            //     q7_t      inA1 = *pA++;
            //     q15_t     inB1 = *pB++;
            //     sum += inA1 * inB1;
            //     colCnt--;
            // }
            *pOut = (q7_t) NDS_DSP_SATS((sum >> out_rshift), 8);
            pOut++;
        }
    }
// #endif
#else
    /* Run the following code as reference implementation for Cortex-M0 and Cortex-M3 */

    uint16_t  i, j, k, l, m, n;
    int       conv_out;
    long in_row, in_col;

    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
    {
        /* check if the input dimension meets the constraints */
        return -1;
    }

    for (i = 0; i < out_tensor_ch; i++)
    {
        for (j = 0; j < out_tensor_dim; j++)
        {
            for (k = 0; k < out_tensor_dim; k++)
            {
                conv_out = (bias[i] << bias_lshift) + NN_ROUND(out_rshift);
                for (m = 0; m < ker_dim; m++)
                {
                    for (n = 0; n < ker_dim; n++)
                    {
                        // if-for implementation
                        in_row = stride * j + m - pad;
                        in_col = stride * k + n - pad;
                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
                        {
                            for (l = 0; l < in_tensor_ch; l++)
                            {
                                conv_out +=
                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
                            }
                        }
                    }
                }
                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q7_t) NDS_ISA_SATS((conv_out >> out_rshift), 8);
            }
        }
    }

#endif                          /* ENA_DSP_ISA */
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

