  19→
  20→/** @file*/
  21→
  22→#include "internal_nn_math.h"
  23→#include "riscv_nn_support.h"
  24→
  25→//// Convolution Functions
  26→
  27→int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sft_bias_fast(const q7_t * in_tensor,
  28→                                    const uint16_t in_tensor_dim,
  29→                                    const q7_t * ker_weight,
  30→                                    const uint16_t out_tensor_ch,
  31→                                    const uint16_t ker_dim,
  32→                                    const uint16_t pad,
  33→                                    const uint16_t stride,
  34→                                    const q7_t * bias,
  35→                                    const uint16_t bias_lshift,
  36→                                    const uint16_t out_rshift,
  37→                                    q7_t * out_tensor,
  38→                                    const uint16_t out_tensor_dim,
  39→                                    q15_t * in_tmp_buf,
  40→                                    q15_t * wt_tmp_buf)
  41→{
  42→#ifdef ENA_EMPTY_FUN
  43→    //empty body
  44→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
  45→    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
  46→
  47→    /*
  48→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
  49→     *  im2col are done to output in q15_t format from q7_t input
  50→     */
  51→    q7_t *pBuffer = (q7_t *)in_tmp_buf;
  52→    q7_t *pOut = out_tensor;
  53→
  54→    long buf_len = (3 * ker_dim * ker_dim + 1);
  55→    long vl;
  56→
  57→    // This part implements the im2col function
  58→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
  59→    {
  60→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
  61→        {
  62→            //init in_tmp_buf
  63→            uint32_t len = buf_len;
  64→            q7_t *pBuffer2 = pBuffer;
  65→            vl = __riscv_vsetvl_e8m1(len);
  66→            vint8m1_t vZero = __riscv_vand(__riscv_vundefined_i8m1(), 0, vl);   //zero
  67→            while(len > 0)
  68→            {
  69→                __riscv_vse8(pBuffer2, vZero, vl);
  70→                len -= vl;
  71→                pBuffer2 += vl;
  72→                vl = __riscv_vsetvl_e8m1(len);
  73→            }
  74→
  75→            // if (i_ker_y < 0)
  76→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
  77→            {
  78→                pBuffer += ker_dim * 3;
  79→            }
  80→
  81→            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
  82→            for (; i_ker_y < bound_y; i_ker_y++)
  83→            {
  84→                // if (i_ker_x < 0)
  85→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
  86→                {
  87→                    pBuffer += 3;
  88→                }
  89→
  90→                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
  91→                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
  92→                long loop = (bound_x - i_ker_x)*3;
  93→                i_ker_x = bound_x;
  94→                while(loop > 0)
  95→                {
  96→                    vl = __riscv_vsetvl_e8m1(loop);
  97→                    vint8m1_t vpPixel = __riscv_vle8_v_i8m1(pPixel, vl);
  98→                    __riscv_vse8(pBuffer, vpPixel, vl);
  99→                    pPixel += vl;
 100→                    pBuffer += vl;
 101→                    loop -= vl;
 102→                }
 103→
 104→                // if (i_ker_x >= in_tensor_dim)
 105→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
 106→                {
 107→                    pBuffer += 3;
 108→                }
 109→            }
 110→
 111→            // if (i_ker_y >= in_tensor_dim)
 112→            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
 113→            {
 114→                pBuffer += ker_dim * 3;
 115→            }
 116→
 117→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
 118→            {
 119→                pOut = nn_mat_mul_kernel_q7((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
 120→                pBuffer = (q7_t *)in_tmp_buf;
 121→            }
 122→        }
 123→    }
 124→
 125→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
 126→    if (pBuffer != (q7_t *)in_tmp_buf)
 127→    {
 128→        unsigned vl;
 129→        const q7_t *p_wt = ker_weight;
 130→        int       i;
 131→        uint16_t  colCnt = 3 * ker_dim * ker_dim;
 132→        // long vlenb = NDS_VEC_CSR_GET_VLENB();
 133→
 134→        vl = __riscv_vsetvl_e32m1(1);
 135→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
 136→
 137→        for (i = 0; i < out_tensor_ch; i++)
 138→        {
 139→            q7_t      *p_in = (q7_t*)in_tmp_buf;
 140→            uint16_t colCnt2 = colCnt;
 141→
 142→            //clear v0~v7
 143→            vl = __riscv_vsetvl_e32m8(colCnt);
 144→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
 145→
 146→            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
 147→            // {
 148→            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 149→            //     //load src1
 150→            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
 151→            //     //load src2
 152→            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
 153→            //     //bump pointers and update loop counter
 154→            //     colCnt2 -= vl;
 155→            //     p_wt += vl;
 156→            //     p_in += vl;
 157→            //     //set the proper avl/SEW/LMUL values for vd4dot
 158→            //     vl >>= 2;
 159→            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 160→            //     //acc += src1 * src2
 161→            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 162→            // }
 163→
 164→            //extra process for the case of vd4dot's avl is not a mutiple of 4
 165→            while(colCnt2 > 0)
 166→            {
 167→                //clean one of the dot product source
 168→                vl = __riscv_vsetvlmax_e8m8();
 169→                vint8m8_t vP_wt_i8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);
 170→
 171→                vl = __riscv_vsetvl_e8m8(colCnt2);
 172→                //load src1
 173→                vP_wt_i8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8, p_wt, vl);
 174→                //load src2
 175→                vint8m8_t vP_in_i8 = __riscv_vle8_v_i8m8(p_in, vl);
 176→                //bump pointers and update loop counter
 177→                colCnt2 -= vl;
 178→                p_wt += vl;
 179→                p_in += vl;
 180→                //set the proper avl/SEW/LMUL values for vd4dot
 181→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
 182→                vl = __riscv_vsetvl_e32m8(vl);
 183→                //acc += src1 * src2
 184→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8, vP_in_i8, vl);
 185→            }
 186→
 187→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
 188→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
 189→
 190→            //add bias back
 191→            vl = __riscv_vsetvl_e32m1(1);
 192→            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
 193→            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
 194→            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
 195→            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
 196→            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);
 197→
 198→            //scale down, clip and store the results
 199→            vl = __riscv_vsetvl_e16mf2(1);
 200→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
 201→            vl = __riscv_vsetvl_e8mf4(1);
 202→            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
 203→            __riscv_vse8(pOut, vSum_i8mf4, vl);
 204→
 205→            bias += vl;
 206→            pOut += vl;
 207→        }
 208→    }
 209→#elif defined(ENA_VEC_ISA_ZVQMAC)
 210→    /* left-over because odd number of output pixels */
 211→    if (pBuffer != (q7_t *)in_tmp_buf)
 212→    {
 213→        const q7_t *pA = ker_weight;
 214→        int i;
 215→        /* basically each time it process 4 entries */
 216→        long colCnt = (3 * ker_dim * ker_dim);
 217→
 218→        //set SEW for 1st time VMV_S_X
 219→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
 220→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 221→
 222→        for (i = 0; i < out_tensor_ch; i++)
 223→        {
 224→            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
 225→            q7_t *pB = (q7_t*)in_tmp_buf;
 226→            long colCnt2 = colCnt;
 227→
 228→            //init
 229→            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
 230→            //clear v8~v15 (acc)
 231→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
 232→
 233→            while(colCnt2 > 0)
 234→            {
 235→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
 236→                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
 237→                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
 238→                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
 239→
 240→                //bump pointers and update loop counter
 241→                colCnt2 -= vl;
 242→                pA += vl;
 243→                pB += vl;
 244→            }
 245→
 246→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 247→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
 248→            //move vr results to gpr
 249→            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
 250→
 251→            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
 252→        }
 253→    }
 254→#endif
 255→#elif defined(ENA_VEC_ISA)
 256→#if defined(ENA_TILING) && (NDS_VEC_RVV_VERSION >= 1000)
 257→    /*
 258→     * Direct convolution with fused bias + requantize (sft variant).
 259→     * Vectorizes across out_tensor_ch with VQMACC.VX.
 260→     * Processes 4 output pixels at a time, sharing weight loads.
 261→     * Eliminates im2col buffer.
 262→     *
 263→     * Register plan:
 264→     *   v0-v3   (M4 e32): Accumulator pixel 1
 265→     *   v4-v7   (M4 e32): Accumulator pixel 2
 266→     *   v8-v11  (M4 e32): Accumulator pixel 3
 267→     *   v12-v15 (M4 e32): Accumulator pixel 4
 268→     *   v16     (M1 e8):  Weight vector load (transposed)
 269→     *   v17     (M1 e8):  Bias load (temp)
 270→     */
 271→    const int in_tensor_ch = 3;
 272→    long i_ker_y, i_ker_x, ch;
 273→
 274→    const long align_byte = 64;
 275→    q7_t *pOut = out_tensor;
 276→    long vl;
 277→
 278→    /* Allocate transposed weight buffer from in_tmp_buf */
 279→    q7_t *src2 = (q7_t *)in_tmp_buf;
 280→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);
 281→
 282→    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
 283→    const long row = out_tensor_ch;
 284→    const long col = ker_dim * ker_dim * in_tensor_ch;
 285→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
 286→
 287→    /* Total output pixels */
 288→    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
 289→    long pixel_idx = 0;
 290→
 291→    /* Process 4 output pixels at a time */
 292→    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
 293→    {
 294→        long out_y1 = pixel_idx / out_tensor_dim;
 295→        long out_x1 = pixel_idx % out_tensor_dim;
 296→        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
 297→        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
 298→        long out_y3 = (pixel_idx + 2) / out_tensor_dim;
 299→        long out_x3 = (pixel_idx + 2) % out_tensor_dim;
 300→        long out_y4 = (pixel_idx + 3) / out_tensor_dim;
 301→        long out_x4 = (pixel_idx + 3) % out_tensor_dim;
 302→
 303→        /* Channel-striping loop: process out_tensor_ch in VLMAX-sized chunks */
 304→        long ch_off = 0;
 305→        while (ch_off < out_tensor_ch)
 306→        {
 307→            long ch_remain = out_tensor_ch - ch_off;
 308→
 309→            /* Load bias (q7) into temp, widen to i32, shift, add rounding */
 310→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 311→            NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
 312→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
 313→            NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
 314→            NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
 315→            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
 316→            NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V17);
 317→            NDS_VEC_VSLL_VX(NDS_VEC_V4, NDS_VEC_V4, bias_lshift);
 318→            NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, NN_ROUND(out_rshift));
 319→            NDS_VEC_VSEXT_VF4(NDS_VEC_V8, NDS_VEC_V17);
 320→            NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, bias_lshift);
 321→            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(out_rshift));
 322→            NDS_VEC_VSEXT_VF4(NDS_VEC_V12, NDS_VEC_V17);
 323→            NDS_VEC_VSLL_VX(NDS_VEC_V12, NDS_VEC_V12, bias_lshift);
 324→            NDS_VEC_VADD_VX(NDS_VEC_V12, NDS_VEC_V12, NN_ROUND(out_rshift));
 325→
 326→            /* Set e8/M1 once for all vqmacc accumulation */
 327→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 328→
 329→            if (pad == 0)
 330→            {
 331→                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
 332→                {
 333→                    long in_row1 = out_y1 * stride + i_ker_y;
 334→                    long in_row2 = out_y2 * stride + i_ker_y;
 335→                    long in_row3 = out_y3 * stride + i_ker_y;
 336→                    long in_row4 = out_y4 * stride + i_ker_y;
 337→
 338→                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
 339→                    {
 340→                        long in_col1 = out_x1 * stride + i_ker_x;
 341→                        long in_col2 = out_x2 * stride + i_ker_x;
 342→                        long in_col3 = out_x3 * stride + i_ker_x;
 343→                        long in_col4 = out_x4 * stride + i_ker_x;
 344→                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
 345→
 346→                        for (ch = 0; ch < in_tensor_ch; ch++)
 347→                        {
 348→                            long k_pos = k_base + ch;
 349→                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
 350→                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
 351→                            q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
 352→                            q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
 353→                            q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
 354→                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
 355→                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
 356→                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
 357→                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
 358→                        }
 359→                    }
 360→                }
 361→            }
 362→            else
 363→            {
 364→                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
 365→                {
 366→                    long in_row1 = out_y1 * stride - pad + i_ker_y;
 367→                    long in_row2 = out_y2 * stride - pad + i_ker_y;
 368→                    long in_row3 = out_y3 * stride - pad + i_ker_y;
 369→                    long in_row4 = out_y4 * stride - pad + i_ker_y;
 370→
 371→                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
 372→                    {
 373→                        long in_col1 = out_x1 * stride - pad + i_ker_x;
 374→                        long in_col2 = out_x2 * stride - pad + i_ker_x;
 375→                        long in_col3 = out_x3 * stride - pad + i_ker_x;
 376→                        long in_col4 = out_x4 * stride - pad + i_ker_x;
 377→                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
 378→
 379→                        for (ch = 0; ch < in_tensor_ch; ch++)
 380→                        {
 381→                            long k_pos = k_base + ch;
 382→                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
 383→                            q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
 384→                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
 385→                                in_col1 >= 0 && in_col1 < in_tensor_dim)
 386→                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
 387→                            if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
 388→                                in_col2 >= 0 && in_col2 < in_tensor_dim)
 389→                                a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
 390→                            if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
 391→                                in_col3 >= 0 && in_col3 < in_tensor_dim)
 392→                                a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
 393→                            if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
 394→                                in_col4 >= 0 && in_col4 < in_tensor_dim)
 395→                                a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
 396→                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
 397→                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
 398→                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
 399→                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
 400→                        }
 401→                    }
 402→                }
 403→            }
 404→
 405→            /* Requantize pixel 1: narrow to i16, clip to i8, store */
 406→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
 407→            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
 408→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 409→            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
 410→            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);
 411→
 412→            /* Requantize pixel 2 */
 413→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
 414→            NDS_VEC_VNSRA_WX(NDS_VEC_V4, NDS_VEC_V4, out_rshift);
 415→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 416→            NDS_VEC_VNCLIP_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
 417→            NDS_VEC_VSB_V(NDS_VEC_V4, pOut + out_tensor_ch + ch_off);
 418→
 419→            /* Requantize pixel 3 */
 420→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
 421→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
 422→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 423→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
 424→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut + 2 * out_tensor_ch + ch_off);
 425→
 426→            /* Requantize pixel 4 */
 427→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
 428→            NDS_VEC_VNSRA_WX(NDS_VEC_V12, NDS_VEC_V12, out_rshift);
 429→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 430→            NDS_VEC_VNCLIP_WI(NDS_VEC_V12, NDS_VEC_V12, 0);
 431→            NDS_VEC_VSB_V(NDS_VEC_V12, pOut + 3 * out_tensor_ch + ch_off);
 432→
 433→            ch_off += vl;
 434→        }
 435→        pOut += 4 * out_tensor_ch;
 436→    }
 437→
 438→    /* Handle remaining 0-3 pixels one at a time */
 439→    for (; pixel_idx < total_pixels; pixel_idx++)
 440→    {
 441→        long out_y1 = pixel_idx / out_tensor_dim;
 442→        long out_x1 = pixel_idx % out_tensor_dim;
 443→
 444→        long ch_off = 0;
 445→        while (ch_off < out_tensor_ch)
 446→        {
 447→            long ch_remain = out_tensor_ch - ch_off;
 448→
 449→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 450→            NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
 451→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
 452→            NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
 453→            NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
 454→            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
 455→
 456→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 457→
 458→            if (pad == 0)
 459→            {
 460→                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
 461→                {
 462→                    long in_row1 = out_y1 * stride + i_ker_y;
 463→                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
 464→                    {
 465→                        long in_col1 = out_x1 * stride + i_ker_x;
 466→                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
 467→                        for (ch = 0; ch < in_tensor_ch; ch++)
 468→                        {
 469→                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base + ch) * out_tensor_ch + ch_off);
 470→                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
 471→                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
 472→                        }
 473→                    }
 474→                }
 475→            }
 476→            else
 477→            {
 478→                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
 479→                {
 480→                    long in_row1 = out_y1 * stride - pad + i_ker_y;
 481→                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
 482→                    {
 483→                        long in_col1 = out_x1 * stride - pad + i_ker_x;
 484→                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
 485→                        for (ch = 0; ch < in_tensor_ch; ch++)
 486→                        {
 487→                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base + ch) * out_tensor_ch + ch_off);
 488→                            q7_t a1 = 0;
 489→                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
 490→                                in_col1 >= 0 && in_col1 < in_tensor_dim)
 491→                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
 492→                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
 493→                        }
 494→                    }
 495→                }
 496→            }
 497→
 498→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
 499→            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
 500→            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 501→            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
 502→            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);
 503→
 504→            ch_off += vl;
 505→        }
 506→        pOut += out_tensor_ch;
 507→    }
 508→#else  /* ENA_TILING && RVV >= 1000 not set: use im2col path */
 509→    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
 510→
 511→    /*
 512→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 513→     *  im2col are done to output in q15_t format from q7_t input
 514→     */
 515→    q7_t *pBuffer = (q7_t *)in_tmp_buf;
 516→    q7_t *pOut = out_tensor;
 517→
 518→    long buf_len = (3 * ker_dim * ker_dim + 1);
 519→    long vl;
 520→
 521→    // This part implements the im2col function
 522→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
 523→    {
 524→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 525→        {
 526→            //init in_tmp_buf
 527→            uint32_t len = buf_len;
 528→            q7_t *pBuffer2 = pBuffer;
 529→            NDS_VEC_VSETVLI_E8(vl, len);
 530→            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //zero
 531→            while(len > 0)
 532→            {
 533→                NDS_VEC_VSB_V(NDS_VEC_V31, pBuffer2);
 534→                len -= vl;
 535→                pBuffer2 += vl;
 536→                NDS_VEC_VSETVLI_E8(vl, len);
 537→            }
 538→
 539→            // if (i_ker_y < 0)
 540→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
 541→            {
 542→                pBuffer += ker_dim * 3;
 543→            }
 544→
 545→            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
 546→            for (; i_ker_y < bound_y; i_ker_y++)
 547→            {
 548→                // if (i_ker_x < 0)
 549→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
 550→                {
 551→                    pBuffer += 3;
 552→                }
 553→
 554→                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
 555→                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
 556→                long loop = (bound_x - i_ker_x)*3;
 557→                i_ker_x = bound_x;
 558→                while(loop > 0)
 559→                {
 560→                    NDS_VEC_VSETVLI_E8(vl, loop);
 561→                    NDS_VEC_VLB_V(NDS_VEC_V0, pPixel);
 562→                    NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
 563→                    pPixel += vl;
 564→                    pBuffer += vl;
 565→                    loop -= vl;
 566→                }
 567→
 568→                // if (i_ker_x >= in_tensor_dim)
 569→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
 570→                {
 571→                    pBuffer += 3;
 572→                }
 573→            }
 574→
 575→            // if (i_ker_y >= in_tensor_dim)
 576→            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
 577→            {
 578→                pBuffer += ker_dim * 3;
 579→            }
 580→
 581→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
 582→            {
 583→                pOut = nn_mat_mul_kernel_q7((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
 584→                pBuffer = (q7_t *)in_tmp_buf;
 585→            }
 586→        }
 587→    }
 588→
 589→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
 590→    if (pBuffer != (q7_t *)in_tmp_buf)
 591→    {
 592→        unsigned vl;
 593→        const q7_t *p_wt = ker_weight;
 594→        int       i;
 595→        uint16_t  colCnt = 3 * ker_dim * ker_dim;
 596→        // long vlenb = NDS_VEC_CSR_GET_VLENB();
 597→
 598→#if (__clang__)
 599→        register const long zero asm ("x0") = 0;
 600→#else
 601→        register const long zero asm ("x0");
 602→#endif
 603→
 604→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 605→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
 606→
 607→        for (i = 0; i < out_tensor_ch; i++)
 608→        {
 609→            q7_t      *p_in = (q7_t*)in_tmp_buf;
 610→            uint16_t colCnt2 = colCnt;
 611→
 612→            //clear v0~v7
 613→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 614→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
 615→
 616→            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
 617→            // {
 618→            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 619→            //     //load src1
 620→            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
 621→            //     //load src2
 622→            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
 623→            //     //bump pointers and update loop counter
 624→            //     colCnt2 -= vl;
 625→            //     p_wt += vl;
 626→            //     p_in += vl;
 627→            //     //set the proper avl/SEW/LMUL values for vd4dot
 628→            //     vl >>= 2;
 629→            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 630→            //     //acc += src1 * src2
 631→            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 632→            // }
 633→
 634→            //extra process for the case of vd4dot's avl is not a mutiple of 4
 635→            while(colCnt2 > 0)
 636→            {
 637→                //clean one of the dot product source
 638→                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 639→                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
 640→
 641→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 642→                //load src1
 643→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
 644→                //load src2
 645→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
 646→                //bump pointers and update loop counter
 647→                colCnt2 -= vl;
 648→                p_wt += vl;
 649→                p_in += vl;
 650→                //set the proper avl/SEW/LMUL values for vd4dot
 651→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
 652→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 653→                //acc += src1 * src2
 654→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 655→            }
 656→
 657→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
 658→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
 659→
 660→            //add bias back
 661→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 662→            NDS_VEC_VLB_V(NDS_VEC_V10, bias);
 663→            NDS_VEC_VSEXT_VF4(NDS_VEC_V9, NDS_VEC_V10);
 664→            NDS_VEC_VSLL_VX(NDS_VEC_V9, NDS_VEC_V9, bias_lshift);
 665→            NDS_VEC_VADD_VX(NDS_VEC_V9, NDS_VEC_V9, NN_ROUND(out_rshift));
 666→            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
 667→
 668→            //scale down, clip and store the results
 669→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
 670→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
 671→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 672→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
 673→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
 674→
 675→            bias += vl;
 676→            pOut += vl;
 677→        }
 678→    }
 679→#elif defined(ENA_VEC_ISA_ZVQMAC)
 680→    /* left-over because odd number of output pixels */
 681→    if (pBuffer != (q7_t *)in_tmp_buf)
 682→    {
 683→        const q7_t *pA = ker_weight;
 684→        int i;
 685→        /* basically each time it process 4 entries */
 686→        long colCnt = (3 * ker_dim * ker_dim);
 687→
 688→        //set SEW for 1st time VMV_S_X
 689→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
 690→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 691→
 692→        for (i = 0; i < out_tensor_ch; i++)
 693→        {
 694→            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
 695→            q7_t *pB = (q7_t*)in_tmp_buf;
 696→            long colCnt2 = colCnt;
 697→
 698→            //init
 699→            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
 700→            //clear v8~v15 (acc)
 701→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
 702→
 703→            while(colCnt2 > 0)
 704→            {
 705→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
 706→                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
 707→                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
 708→                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
 709→                //bump pointers and update loop counter
 710→                colCnt2 -= vl;
 711→                pA += vl;
 712→                pB += vl;
 713→            }
 714→
 715→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 716→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
 717→            //move vr results to gpr
 718→            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
 719→
 720→            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
 721→        }
 722→    }
 723→#endif
 724→#endif  /* ENA_TILING && NDS_VEC_RVV_VERSION >= 1000 */
 725→#elif defined(ENA_DSP_ISA_V5)
 726→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
 727→
 728→    q7_t *wt_tmp = (q7_t*)ker_weight;
 729→    q7_t    *pBuffer = (q7_t *)in_tmp_buf;
