 918→                pBuffer = in_tmp_buf;
 919→            }
 920→        }
 921→    }
 922→
 923→    if (pBuffer != in_tmp_buf)
 924→    {
 925→        const q7_t *pA = ker_weight;
 926→        int       i;
 927→
 928→        for (i = 0; i < out_tensor_ch; i++)
 929→        {
 930→            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
 931→            q15_t    *pB = in_tmp_buf;
 932→
 933→            /* basically each time it process 4 entries */
 934→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
 935→
