/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions

int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sft_bias_fast(const q7_t * in_tensor,
                                    const uint16_t in_tensor_dim,
                                    const q7_t * ker_weight,
                                    const uint16_t out_tensor_ch,
                                    const uint16_t ker_dim,
                                    const uint16_t pad,
                                    const uint16_t stride,
                                    const q7_t * bias,
                                    const uint16_t bias_lshift,
                                    const uint16_t out_rshift,
                                    q7_t * out_tensor,
                                    const uint16_t out_tensor_dim,
                                    q15_t * in_tmp_buf,
                                    q15_t * wt_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    q7_t *pOut = out_tensor;

    long buf_len = (3 * ker_dim * ker_dim + 1);
    long vl;

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            //init in_tmp_buf
            uint32_t len = buf_len;
            q7_t *pBuffer2 = pBuffer;
            vl = __riscv_vsetvl_e8m1(len);
            vint8m1_t vZero = __riscv_vand(__riscv_vundefined_i8m1(), 0, vl);   //zero
            while(len > 0)
            {
                __riscv_vse8(pBuffer2, vZero, vl);
                len -= vl;
                pBuffer2 += vl;
                vl = __riscv_vsetvl_e8m1(len);
            }

            // if (i_ker_y < 0)
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
            for (; i_ker_y < bound_y; i_ker_y++)
            {
                // if (i_ker_x < 0)
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
                {
                    pBuffer += 3;
                }

                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                long loop = (bound_x - i_ker_x)*3;
                i_ker_x = bound_x;
                while(loop > 0)
                {
                    vl = __riscv_vsetvl_e8m1(loop);
                    vint8m1_t vpPixel = __riscv_vle8_v_i8m1(pPixel, vl);
                    __riscv_vse8(pBuffer, vpPixel, vl);
                    pPixel += vl;
                    pBuffer += vl;
                    loop -= vl;
                }

                // if (i_ker_x >= in_tensor_dim)
                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    pBuffer += 3;
                }
            }

            // if (i_ker_y >= in_tensor_dim)
            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
            {
                pOut = nn_mat_mul_kernel_q7((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        unsigned vl;
        const q7_t *p_wt = ker_weight;
        int       i;
        uint16_t  colCnt = 3 * ker_dim * ker_dim;
        // long vlenb = NDS_VEC_CSR_GET_VLENB();

        vl = __riscv_vsetvl_e32m1(1);
        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            q7_t      *p_in = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            vl = __riscv_vsetvl_e32m8(colCnt);
            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
            // {
            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            //     //load src1
            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
            //     //load src2
            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
            //     //bump pointers and update loop counter
            //     colCnt2 -= vl;
            //     p_wt += vl;
            //     p_in += vl;
            //     //set the proper avl/SEW/LMUL values for vd4dot
            //     vl >>= 2;
            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //     //acc += src1 * src2
            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            // }

            //extra process for the case of vd4dot's avl is not a mutiple of 4
            while(colCnt2 > 0)
            {
                //clean one of the dot product source
                vl = __riscv_vsetvlmax_e8m8();
                vint8m8_t vP_wt_i8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);

                vl = __riscv_vsetvl_e8m8(colCnt2);
                //load src1
                vP_wt_i8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8, p_wt, vl);
                //load src2
                vint8m8_t vP_in_i8 = __riscv_vle8_v_i8m8(p_in, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                //remember to deal with the avl of vd4dot is not a multiple of 4 case
                vl = __riscv_vsetvl_e32m8(vl);
                //acc += src1 * src2
                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8, vP_in_i8, vl);
            }

            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);

            //add bias back
            vl = __riscv_vsetvl_e32m1(1);
            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);

            //scale down, clip and store the results
            vl = __riscv_vsetvl_e16mf2(1);
            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
            vl = __riscv_vsetvl_e8mf4(1);
            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
            __riscv_vse8(pOut, vSum_i8mf4, vl);

            bias += vl;
            pOut += vl;
        }
    }
#elif defined(ENA_VEC_ISA_ZVQMAC)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;
        /* basically each time it process 4 entries */
        long colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
            q7_t *pB = (q7_t*)in_tmp_buf;
            long colCnt2 = colCnt;

            //init
            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
            //clear v8~v15 (acc)
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);

                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);

            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
        }
    }
#endif
#elif defined(ENA_VEC_ISA)
#if defined(ENA_TILING) && (NDS_VEC_RVV_VERSION >= 1000)
    /*
     * Direct convolution with fused bias + requantize (sft variant).
     * Vectorizes across out_tensor_ch with VQMACC.VX.
     * Processes 4 output pixels at a time, sharing weight loads.
     * Eliminates im2col buffer.
     *
     * Register plan:
     *   v0-v3   (M4 e32): Accumulator pixel 1
     *   v4-v7   (M4 e32): Accumulator pixel 2
     *   v8-v11  (M4 e32): Accumulator pixel 3
     *   v12-v15 (M4 e32): Accumulator pixel 4
     *   v16     (M1 e8):  Weight vector load (transposed)
     *   v17     (M1 e8):  Bias load (temp)
     */
    const int in_tensor_ch = 3;
    long i_ker_y, i_ker_x, ch;

    const long align_byte = 64;
    q7_t *pOut = out_tensor;
    long vl;

    /* Allocate transposed weight buffer from in_tmp_buf */
    q7_t *src2 = (q7_t *)in_tmp_buf;
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);

    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* Total output pixels */
    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
    long pixel_idx = 0;

    /* Process 4 output pixels at a time */
    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;
        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
        long out_y3 = (pixel_idx + 2) / out_tensor_dim;
        long out_x3 = (pixel_idx + 2) % out_tensor_dim;
        long out_y4 = (pixel_idx + 3) / out_tensor_dim;
        long out_x4 = (pixel_idx + 3) % out_tensor_dim;

        /* Channel-striping loop: process out_tensor_ch in VLMAX-sized chunks */
        long ch_off = 0;
        while (ch_off < out_tensor_ch)
        {
            long ch_remain = out_tensor_ch - ch_off;

            /* Load bias (q7) into temp, widen to i32, shift, add rounding */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
            NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
            NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V17);
            NDS_VEC_VSLL_VX(NDS_VEC_V4, NDS_VEC_V4, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, NN_ROUND(out_rshift));
            NDS_VEC_VSEXT_VF4(NDS_VEC_V8, NDS_VEC_V17);
            NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(out_rshift));
            NDS_VEC_VSEXT_VF4(NDS_VEC_V12, NDS_VEC_V17);
            NDS_VEC_VSLL_VX(NDS_VEC_V12, NDS_VEC_V12, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V12, NDS_VEC_V12, NN_ROUND(out_rshift));

            /* Set e8/M1 once for all vqmacc accumulation */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

            if (pad == 0)
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride + i_ker_y;
                    long in_row2 = out_y2 * stride + i_ker_y;
                    long in_row3 = out_y3 * stride + i_ker_y;
                    long in_row4 = out_y4 * stride + i_ker_y;

                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride + i_ker_x;
                        long in_col2 = out_x2 * stride + i_ker_x;
                        long in_col3 = out_x3 * stride + i_ker_x;
                        long in_col4 = out_x4 * stride + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                            q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                            q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }
            else
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride - pad + i_ker_y;
                    long in_row2 = out_y2 * stride - pad + i_ker_y;
                    long in_row3 = out_y3 * stride - pad + i_ker_y;
                    long in_row4 = out_y4 * stride - pad + i_ker_y;

                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride - pad + i_ker_x;
                        long in_col2 = out_x2 * stride - pad + i_ker_x;
                        long in_col3 = out_x3 * stride - pad + i_ker_x;
                        long in_col4 = out_x4 * stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                            q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                                in_col1 >= 0 && in_col1 < in_tensor_dim)
                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                                in_col2 >= 0 && in_col2 < in_tensor_dim)
                                a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                            if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
                                in_col3 >= 0 && in_col3 < in_tensor_dim)
                                a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                            if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
                                in_col4 >= 0 && in_col4 < in_tensor_dim)
                                a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }

            /* Requantize pixel 1: narrow to i16, clip to i8, store */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

            /* Requantize pixel 2 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V4, NDS_VEC_V4, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
            NDS_VEC_VSB_V(NDS_VEC_V4, pOut + out_tensor_ch + ch_off);

            /* Requantize pixel 3 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSB_V(NDS_VEC_V8, pOut + 2 * out_tensor_ch + ch_off);

            /* Requantize pixel 4 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V12, NDS_VEC_V12, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V12, NDS_VEC_V12, 0);
            NDS_VEC_VSB_V(NDS_VEC_V12, pOut + 3 * out_tensor_ch + ch_off);

            ch_off += vl;
        }
        pOut += 4 * out_tensor_ch;
    }

    /* Handle remaining 0-3 pixels one at a time */
    for (; pixel_idx < total_pixels; pixel_idx++)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;

        long ch_off = 0;
        while (ch_off < out_tensor_ch)
        {
            long ch_remain = out_tensor_ch - ch_off;

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
            NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

            if (pad == 0)
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base + ch) * out_tensor_ch + ch_off);
                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        }
                    }
                }
            }
            else
            {
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride - pad + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base + ch) * out_tensor_ch + ch_off);
                            q7_t a1 = 0;
                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                                in_col1 >= 0 && in_col1 < in_tensor_dim)
                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        }
                    }
                }
            }

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

            ch_off += vl;
        }
        pOut += out_tensor_ch;
    }
#else  /* ENA_TILING && RVV >= 1000 not set: use im2col path */
    long   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    q7_t *pOut = out_tensor;

    long buf_len = (3 * ker_dim * ker_dim + 1);
    long vl;

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            //init in_tmp_buf
            uint32_t len = buf_len;
            q7_t *pBuffer2 = pBuffer;
            NDS_VEC_VSETVLI_E8(vl, len);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //zero
            while(len > 0)
            {
                NDS_VEC_VSB_V(NDS_VEC_V31, pBuffer2);
                len -= vl;
                pBuffer2 += vl;
                NDS_VEC_VSETVLI_E8(vl, len);
            }

            // if (i_ker_y < 0)
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
            for (; i_ker_y < bound_y; i_ker_y++)
            {
                // if (i_ker_x < 0)
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
                {
                    pBuffer += 3;
                }

                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                long loop = (bound_x - i_ker_x)*3;
                i_ker_x = bound_x;
                while(loop > 0)
                {
                    NDS_VEC_VSETVLI_E8(vl, loop);
                    NDS_VEC_VLB_V(NDS_VEC_V0, pPixel);
                    NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
                    pPixel += vl;
                    pBuffer += vl;
                    loop -= vl;
                }

                // if (i_ker_x >= in_tensor_dim)
                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    pBuffer += 3;
                }
            }

            // if (i_ker_y >= in_tensor_dim)
            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
            {
                pOut = nn_mat_mul_kernel_q7((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, bias_lshift, out_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        unsigned vl;
        const q7_t *p_wt = ker_weight;
        int       i;
        uint16_t  colCnt = 3 * ker_dim * ker_dim;
        // long vlenb = NDS_VEC_CSR_GET_VLENB();

#if (__clang__)
        register const long zero asm ("x0") = 0;
#else
        register const long zero asm ("x0");
#endif

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            q7_t      *p_in = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);

            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
            // {
            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            //     //load src1
            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
            //     //load src2
            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
            //     //bump pointers and update loop counter
            //     colCnt2 -= vl;
            //     p_wt += vl;
            //     p_in += vl;
            //     //set the proper avl/SEW/LMUL values for vd4dot
            //     vl >>= 2;
            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //     //acc += src1 * src2
            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            // }

            //extra process for the case of vd4dot's avl is not a mutiple of 4
            while(colCnt2 > 0)
            {
                //clean one of the dot product source
                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);

                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                //load src1
                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
                //load src2
                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                //remember to deal with the avl of vd4dot is not a multiple of 4 case
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                //acc += src1 * src2
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);

            //add bias back
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V10, bias);
            NDS_VEC_VSEXT_VF4(NDS_VEC_V9, NDS_VEC_V10);
            NDS_VEC_VSLL_VX(NDS_VEC_V9, NDS_VEC_V9, bias_lshift);
            NDS_VEC_VADD_VX(NDS_VEC_V9, NDS_VEC_V9, NN_ROUND(out_rshift));
            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);

            //scale down, clip and store the results
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);

            bias += vl;
            pOut += vl;
        }
    }
#elif defined(ENA_VEC_ISA_ZVQMAC)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;
        /* basically each time it process 4 entries */
        long colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
            q7_t *pB = (q7_t*)in_tmp_buf;
            long colCnt2 = colCnt;

            //init
            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
            //clear v8~v15 (acc)
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);

            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
        }
    }
#endif
#endif  /* ENA_TILING && NDS_VEC_RVV_VERSION >= 1000 */
#elif defined(ENA_DSP_ISA_V5)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    q7_t *wt_tmp = (q7_t*)ker_weight;
    q7_t    *pBuffer = (q7_t *)in_tmp_buf;
    q7_t     *pOut = out_tensor;

    uint32_t i;
    q7_t    *pBufferB = (q7_t *)wt_tmp_buf;

    uint16_t totalsize = 3 * ker_dim * ker_dim;
    for (i = 0; i < out_tensor_ch; i++)
    {
        uint32_t j;
        for (j = 0; j < totalsize; j++)
        {
            *pBufferB++ = *wt_tmp++;
        }
        *pBufferB++ = 0;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q7((q7_t *)wt_tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, bias_lshift, out_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* left-over because odd number of output pixels */
#ifdef ENA_DSP_ISA_64
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = 0;
            q7_t *pB = (q7_t*)in_tmp_buf;

            /* basically each time it process 8 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;

            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD64(pA)++;
                inB1 = *__SIMD64(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }

            //sum up the high and low part results (SIMD results)
            sum = (q31_t)(sum >> 32) + (q31_t)sum;

            colCnt = 3 * ker_dim * ker_dim & 0x7;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            /* add bias back in to sum */
            sum += ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);

            *pOut++ = NDS_DSP_SATS((sum >> out_rshift), 8);
        }
    }
#else
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
            q7_t *pB = (q7_t*)in_tmp_buf;

            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD32(pA)++;
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }

            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            *pOut++ = NDS_DSP_SATS((sum >> out_rshift), 8);
        }
    }
#endif
#elif defined(ENA_DSP_ISA)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;
    q15_t    *pBuffer = in_tmp_buf;
    q7_t     *pOut = out_tensor;

    uint32_t i;
    uint16_t size;
    uint16_t size2 = (3 * ker_dim * ker_dim) >> 2;
    q31_t tmp;
    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
    for (i = 0; i < out_tensor_ch; i++)
    {
        size = size2;
        while (size != 0)
        {
            tmp = *__SIMD32(wt_tmp)++;;
            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
            size--;
        }
        q7_t tmp1 = *wt_tmp++;
        q7_t tmp2 = *wt_tmp++;
        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
        tmp1 = *wt_tmp++;
        *pwt2++ = (u16_t)tmp1;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q15(wt_tmp_buf, in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, bias_lshift, out_rshift, bias, pOut);
                pBuffer = in_tmp_buf;
            }
        }
    }

    if (pBuffer != in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int       i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
            q15_t    *pB = in_tmp_buf;

            /* basically each time it process 4 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;

            while (colCnt)
            {

                q31_t     inA1, inA2;
                q31_t     inB1, inB2;

                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA1, inB1);
                inB2 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA2, inB2);

                colCnt--;
            }
            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t      inA1 = *pA++;
                q15_t     inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }
            *pOut++ = (q7_t) NDS_DSP_SATS((sum >> out_rshift), 8);
        }
    }
#else
    uint16_t  i, j, k, l, m, n;
    int       conv_out;
    long in_row, in_col;

    for (i = 0; i < out_tensor_ch; i++)
    {
        for (j = 0; j < out_tensor_dim; j++)
        {
            for (k = 0; k < out_tensor_dim; k++)
            {
                conv_out = (bias[i] << bias_lshift) + NN_ROUND(out_rshift);
                for (m = 0; m < ker_dim; m++)
                {
                    for (n = 0; n < ker_dim; n++)
                    {
                        /* if-for implementation */
                        in_row = stride * j + m - pad;
                        in_col = stride * k + n - pad;
                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
                        {
                            for (l = 0; l < 3; l++)
                            {
                                conv_out +=
                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
                            }
                        }
                    }
                }
                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q7_t) NDS_ISA_SATS((conv_out >> out_rshift), 8);
            }
        }
    }

#endif                          /* ENA_DSP_ISA */

    return 0;
}

input.old_string:
/*
 * Direct convolution with fused bias + requantize (sft variant).
 * Vectorizes across out_tensor_ch with VQMACC.VX.
 * Processes 4 output pixels at a time, sharing weight loads.
 * Eliminates im2col buffer.
 *
 * Register plan:
 *   v0-v3   (M4 e32): Accumulator pixel 1
 *   v4-v7   (M4 e32): Accumulator pixel 2
 *   v8-v11  (M4 e32): Accumulator pixel 3
 *   v12-v15 (M4 e32): Accumulator pixel 4
 *   v16     (M1 e8):  Weight vector load (transposed)
 *   v17     (M1 e8):  Bias load (temp)
 */
const int in_tensor_ch = 3;
long i_ker_y, i_ker_x, ch;

const long align_byte = 64;
q7_t *pOut = out_tensor;
long vl;

/* Allocate transposed weight buffer from in_tmp_buf */
q7_t *src2 = (q7_t *)in_tmp_buf;
src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);

/* Transpose weights once: from [out_ch x K] to [K x out_ch] */
const long row = out_tensor_ch;
const long col = ker_dim * ker_dim * in_tensor_ch;
nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

/* Total output pixels */
long total_pixels = (long)out_tensor_dim * out_tensor_dim;
long pixel_idx = 0;

/* Process 4 output pixels at a time */
for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
{
    long out_y1 = pixel_idx / out_tensor_dim;
    long out_x1 = pixel_idx % out_tensor_dim;
    long out_y2 = (pixel_idx + 1) / out_tensor_dim;
    long out_x2 = (pixel_idx + 1) % out_tensor_dim;
    long out_y3 = (pixel_idx + 2) / out_tensor_dim;
    long out_x3 = (pixel_idx + 2) % out_tensor_dim;
    long out_y4 = (pixel_idx + 3) / out_tensor_dim;
    long out_x4 = (pixel_idx + 3) % out_tensor_dim;

    /* Channel-striping loop: process out_tensor_ch in VLMAX-sized chunks */
    long ch_off = 0;
    while (ch_off < out_tensor_ch)
    {
        long ch_remain = out_tensor_ch - ch_off;

        /* Load bias (q7) into temp, widen to i32, shift, add rounding */
        NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
        NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
        NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
        NDS_VEC_VSEXT_VF4(NDS_VEC_V4, NDS_VEC_V17);
        NDS_VEC_VSLL_VX(NDS_VEC_V4, NDS_VEC_V4, bias_lshift);
        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, NN_ROUND(out_rshift));
        NDS_VEC_VSEXT_VF4(NDS_VEC_V8, NDS_VEC_V17);
        NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, bias_lshift);
        NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(out_rshift));
        NDS_VEC_VSEXT_VF4(NDS_VEC_V12, NDS_VEC_V17);
        NDS_VEC_VSLL_VX(NDS_VEC_V12, NDS_VEC_V12, bias_lshift);
        NDS_VEC_VADD_VX(NDS_VEC_V12, NDS_VEC_V12, NN_ROUND(out_rshift));

        /* Set e8/M1 once for all vqmacc accumulation */
        NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

        if (pad == 0)
        {
            for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
            {
                long in_row1 = out_y1 * stride + i_ker_y;
                long in_row2 = out_y2 * stride + i_ker_y;
                long in_row3 = out_y3 * stride + i_ker_y;
                long in_row4 = out_y4 * stride + i_ker_y;

                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                {
                    long in_col1 = out_x1 * stride + i_ker_x;
                    long in_col2 = out_x2 * stride + i_ker_x;
                    long in_col3 = out_x3 * stride + i_ker_x;
                    long in_col4 = out_x4 * stride + i_ker_x;
                    long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                    for (ch = 0; ch < in_tensor_ch; ch++)
                    {
                        long k_pos = k_base + ch;
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                        q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                        q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                        q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                        q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                    }
                }
            }
        }
        else
        {
            for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
            {
                long in_row1 = out_y1 * stride - pad + i_ker_y;
                long in_row2 = out_y2 * stride - pad + i_ker_y;
                long in_row3 = out_y3 * stride - pad + i_ker_y;
                long in_row4 = out_y4 * stride - pad + i_ker_y;

                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                {
                    long in_col1 = out_x1 * stride - pad + i_ker_x;
                    long in_col2 = out_x2 * stride - pad + i_ker_x;
                    long in_col3 = out_x3 * stride - pad + i_ker_x;
                    long in_col4 = out_x4 * stride - pad + i_ker_x;
                    long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                    for (ch = 0; ch < in_tensor_ch; ch++)
                    {
                        long k_pos = k_base + ch;
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                        q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
                        if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                            in_col1 >= 0 && in_col1 < in_tensor_dim)
                            a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                        if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                            in_col2 >= 0 && in_col2 < in_tensor_dim)
                            a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                        if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
                            in_col3 >= 0 && in_col3 < in_tensor_dim)
                            a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                        if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
                            in_col4 >= 0 && in_col4 < in_tensor_dim)
                            a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                    }
                }
            }
        }

        /* Requantize pixel 1: narrow to i16, clip to i8, store */
        NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
