                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++) { \
                    long _ic = (long)(ox) * stride - pad + i_ker_x; \
                    long _kb = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch; \
                    for (ch = 0; ch < in_tensor_ch; ch++) { \
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (_kb + ch) * N + _ch_off); \
                        q7_t _a = 0; \
                        if (_ir >= 0 && _ir < in_tensor_dim && \
                            _ic >= 0 && _ic < in_tensor_dim) \
                            _a = in_tensor[(_ir * in_tensor_dim + _ic) * in_tensor_ch + ch]; \
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, _a, NDS_VEC_V16); \
                    } \
                } \
            } \
            NDS_VEC_VSETVLI(vl, _ch_rem, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2); \
            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift); \
            NDS_VEC_VSETVLI(vl, _ch_rem, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1); \
            NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0); \
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + _ch_off); \
            _ch_off += vl; \
        } \
        pOut += out_tensor_ch; \
    } while(0)

    /* Top border rows */
    for (out_y = 0; out_y < y_int_start; out_y++)
        for (out_x = 0; out_x < out_tensor_dim; out_x++)
            BORDER_PIXEL(out_y, out_x);

    /* Interior rows */
    for (out_y = y_int_start; out_y < y_int_end; out_y++)
    {
        /* Left border pixels */
        for (out_x = 0; out_x < x_int_start; out_x++)
            BORDER_PIXEL(out_y, out_x);

        /* Interior 4-pixel batches: no bounds checks */
        for (out_x = x_int_start; out_x + 3 < x_int_end; out_x += 4)
        {
            long ch_off = 0;
            while (ch_off < out_tensor_ch)
            {
                long ch_remain = out_tensor_ch - ch_off;

                /* Bias init + copy to all 4 accumulators */
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
                NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
                NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
                NDS_VEC_VMV4R_V(NDS_VEC_V4, NDS_VEC_V0);
                NDS_VEC_VMV4R_V(NDS_VEC_V8, NDS_VEC_V0);
                NDS_VEC_VMV4R_V(NDS_VEC_V12, NDS_VEC_V0);

                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

                /* K loop: no bounds checks needed */
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row = out_y * stride - pad + i_ker_y;

                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col_base = out_x * stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * N + ch_off);
                            const q7_t *pix = in_tensor + (in_row * in_tensor_dim + in_col_base) * in_tensor_ch + ch;
                            q7_t a1 = pix[0];
                            q7_t a2 = pix[stride * in_tensor_ch];
                            q7_t a3 = pix[2 * stride * in_tensor_ch];
                            q7_t a4 = pix[3 * stride * in_tensor_ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }

                /* Requantize and store 4 pixels */
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNSRA_WX(NDS_VEC_V4, NDS_VEC_V4, out_rshift);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
                NDS_VEC_VSB_V(NDS_VEC_V4, pOut + out_tensor_ch + ch_off);

                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSB_V(NDS_VEC_V8, pOut + 2 * out_tensor_ch + ch_off);

                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNSRA_WX(NDS_VEC_V12, NDS_VEC_V12, out_rshift);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V12, NDS_VEC_V12, 0);
                NDS_VEC_VSB_V(NDS_VEC_V12, pOut + 3 * out_tensor_ch + ch_off);

                ch_off += vl;
            }
            pOut += 4 * out_tensor_ch;
        }

        /* Interior leftover pixels (no bounds checks, 1 at a time) */
        for (; out_x < x_int_end; out_x++)
        {
            long ch_off = 0;
            while (ch_off < out_tensor_ch)
            {
                long ch_remain = out_tensor_ch - ch_off;
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLB_V(NDS_VEC_V17, bias + ch_off);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                NDS_VEC_VSEXT_VF4(NDS_VEC_V0, NDS_VEC_V17);
                NDS_VEC_VSLL_VX(NDS_VEC_V0, NDS_VEC_V0, bias_lshift);
                NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(out_rshift));
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row = out_y * stride - pad + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col = out_x * stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + (k_base + ch) * N + ch_off);
                            q7_t a = in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a, NDS_VEC_V16);
                        }
                    }
                }
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
                NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);
                ch_off += vl;
            }
            pOut += out_tensor_ch;
        }

        /* Right border pixels */
        for (out_x = x_int_end; out_x < out_tensor_dim; out_x++)
            BORDER_PIXEL(out_y, out_x);
    }

    /* Bottom border rows */
    for (out_y = y_int_end; out_y < out_tensor_dim; out_y++)
        for (out_x = 0; out_x < out_tensor_dim; out_x++)
            BORDER_PIXEL(out_y, out_x);

    #undef BORDER_PIXEL
#else  /* ENA_TILING not set: use im2col path */
    long   i_out_y, i_out_x, i_ker_y, i_ker_x;

